import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    /** Counts how many elements equal the given value. */
    private int count(String[] arr, String val) {
        int c = 0;
        for (String s : arr) if (val.equals(s)) c++;
        return c;
    }

    /** Asserts that all APPROVED entries precede all PENDING entries. */
    private void assertPartitioned(String[] arr) {
        boolean seenPending = false;
        for (String s : arr) {
            if ("PENDING".equals(s)) seenPending = true;
            if (seenPending && "APPROVED".equals(s)) {
                fail("Found APPROVED after PENDING — array is not partitioned: " + java.util.Arrays.toString(arr));
            }
        }
    }

    @Test
    void basic() {
        String[] s = {"PENDING", "APPROVED", "PENDING", "APPROVED"};
        new Solution().partitionByStatus(s);
        assertEquals(2, count(s, "APPROVED"));
        assertEquals(2, count(s, "PENDING"));
        assertPartitioned(s);
    }

    @Test
    void allApproved() {
        String[] s = {"APPROVED", "APPROVED", "APPROVED"};
        new Solution().partitionByStatus(s);
        assertEquals(3, count(s, "APPROVED"));
        assertEquals(0, count(s, "PENDING"));
        assertPartitioned(s);
    }

    @Test
    void allPending() {
        String[] s = {"PENDING", "PENDING", "PENDING"};
        new Solution().partitionByStatus(s);
        assertEquals(0, count(s, "APPROVED"));
        assertEquals(3, count(s, "PENDING"));
        assertPartitioned(s);
    }

    @Test
    void single_approved() {
        String[] s = {"APPROVED"};
        new Solution().partitionByStatus(s);
        assertEquals(1, count(s, "APPROVED"));
        assertPartitioned(s);
    }

    @Test
    void single_pending() {
        String[] s = {"PENDING"};
        new Solution().partitionByStatus(s);
        assertEquals(1, count(s, "PENDING"));
        assertPartitioned(s);
    }

    @Test
    void empty() {
        String[] s = {};
        new Solution().partitionByStatus(s);
        assertEquals(0, s.length);
    }

    @Test
    void alternating() {
        // adversarial: strictly alternating starting with APPROVED
        String[] s = {"APPROVED", "PENDING", "APPROVED", "PENDING", "APPROVED", "PENDING"};
        new Solution().partitionByStatus(s);
        assertEquals(3, count(s, "APPROVED"));
        assertEquals(3, count(s, "PENDING"));
        assertPartitioned(s);
    }
}
